noncompliant:
public class Foo
{
    [ThreadStatic]
    private int count; // Noncompliant - ThreadStatic is ignored on non-static fields
}

public class Bar
{
    [ThreadStatic]
    public string name = "default"; // Noncompliant - attribute has no effect
}

compliant:
public class Foo
{
    [ThreadStatic]
    private static int count; // Compliant - field is static
}

public class Bar
{
    private ThreadLocal<string> name = new ThreadLocal<string>(() => "default"); // Compliant - use ThreadLocal for instance fields
}

public class Baz
{
    private int count; // Compliant - remove ThreadStatic if you don't need thread-local storage
}
